import React, { useState, useEffect } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { FaHome, FaCog, FaBars, FaTimes, FaEdit, FaTrash } from "react-icons/fa";
import './home.css';

function Home() {
  const [user, setUser] = useState({
    name: "Kekli Abdesslem",
    bio: "Technicien support IT passionné par les réseaux et la technologie.",
    profilePicture: "https://via.placeholder.com/150",
    coverPhoto: "https://via.placeholder.com/800x300",
  });

  const [showModal, setShowModal] = useState(false);
  const [editName, setEditName] = useState(user.name);
  const [editBio, setEditBio] = useState(user.bio);

  const [isOpen, setIsOpen] = useState(true);

  // Handle the sidebar toggle
  const toggleSidebar = () => {
    setIsOpen(!isOpen);
  };

  // Function to convert image to base64
  const convertToBase64 = (file, callback) => {
    const reader = new FileReader();
    reader.onload = () => {
      callback(reader.result);
    };
    reader.readAsDataURL(file);
  };

  const handleProfilePictureChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      convertToBase64(file, (base64) => {
        setUser({ ...user, profilePicture: base64 });
      });
    }
  };

  const handleCoverPhotoChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      convertToBase64(file, (base64) => {
        setUser({ ...user, coverPhoto: base64 });
      });
    }
  };

  const handleEdit = () => {
    setUser({ ...user, name: editName, bio: editBio });
    setShowModal(false);
  };

  const handleDelete = () => {
    const confirmDelete = window.confirm("Êtes-vous sûr de vouloir supprimer votre compte ?");
    if (confirmDelete) {
      alert("Votre compte a été supprimé !");
    }
  };

  return (
    <div className="home-container">
      {/* Sidebar */}
      <div className={`sidebar ${isOpen ? "open" : "closed"}`}>
        <button className="toggle-btn" onClick={toggleSidebar}>
          {isOpen ? <FaTimes /> : <FaBars />}
        </button>
        <ul>
          <li>
            <FaHome /> {isOpen && <span>Home</span>}
          </li>
          <li>
            <FaCog /> {isOpen && <span>Settings</span>}
          </li>
        </ul>
      </div>

      {/* Main Content */}
      <div className="main-content">
        <div className="profile-header">
          {/* Cover photo */}
          <div className="cover-photo-container">
            <img src={user.coverPhoto} alt="Couverture" className="cover-photo" />
            <label className="upload-cover-label">
              Changer la couverture
              <input type="file" style={{ display: 'none' }} onChange={handleCoverPhotoChange} />
            </label>
            <img src={user.profilePicture} alt="Profil utilisateur" className="profile-picture" />
            <label className="upload-profile-label">
              Changer la photo
              <input type="file" style={{ display: 'none' }} onChange={handleProfilePictureChange} />
            </label>
          </div>
          {/* User Info */}
          <div className="info-section">
            <h2>{user.name}</h2>
            <p>{user.bio}</p>
          </div>
        </div>

        {/* Action buttons */}
        <div className="action-buttons">
          <button onClick={() => setShowModal(true)}>Modifier le profil</button>
          <button onClick={handleDelete}>Supprimer mon compte</button>
        </div>

        {/* Modal for editing profile */}
        {showModal && (
          <div className="modal-overlay">
            <div className="modal">
              <h2>Modifier le profil</h2>
              <div className="modal-field">
                <label>Nom :</label>
                <input type="text" value={editName} onChange={(e) => setEditName(e.target.value)} />
              </div>
              <div className="modal-field">
                <label>Bio :</label>
                <textarea value={editBio} onChange={(e) => setEditBio(e.target.value)} />
              </div>
              <div className="modal-actions">
                <button onClick={handleEdit}>Sauvegarder</button>
                <button onClick={() => setShowModal(false)}>Annuler</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Home;
